import React, { useContext, useState, useEffect } from "react";
import {
  View,
  Text,
  StyleSheet,
  Pressable,
  ActivityIndicator,
  ScrollView,
} from "react-native";
import { AppContext } from "../../../App";
import { completeVerification } from "../../api/verificationApi";
import { useFormNavigation } from "../../utils/navigationUtils";
import Header from "../../components/Header";
import { useTranslation } from "../../i18n";

const COLORS = {
  primary: "#14B8A6",
  secondary: "#7C3AED",
  background: "#F7F9FA",
  card: "#FFFFFF",
  textDark: "#111827",
  textMuted: "#6B7280",
  border: "#E5E7EB",
  success: "#16A34A",
  danger: "#DC2626",
};

export default function DocumentCompletionScreen({ navigation }) {
  const { verification, setFormProgress, clearAllData } = useContext(AppContext);
  const { updateCurrentStep } = useFormNavigation();
  const { t } = useTranslation();

  const [saving, setSaving] = useState(false);
  const [completed, setCompleted] = useState(false);

  useEffect(() => {
    updateCurrentStep("document_upload_completion_screen");
  }, []);

  const handleFinish = async () => {
    try {
      setSaving(true);
      // await completeVerification(verification.verificationId);

      setCompleted(true);

      setFormProgress((prev) => ({
        ...prev,
        completedSteps: [
          ...new Set([...prev.completedSteps, "document_upload_completion_screen"]),
        ],
        currentStep: "document_upload_completion_screen",
      }));
    } catch (e) {
      console.log("Error completing verification:", e);
    } finally {
      setSaving(false);
    }
  };

  const handleStartNew = () => {
    clearAllData();
    navigation.navigate("ownership_screen");
  };

  if (!completed) {
    return (
      <View style={styles.screen}>
        <Header />
        <ScrollView
          contentContainerStyle={styles.scroll}
          keyboardShouldPersistTaps="handled"
        >
          {/* Header */}
          <View style={styles.header}>
            <View style={styles.badge}>
              <Text style={styles.badgeText}>
                {t("completion.verificationBadge")}
              </Text>
            </View>

            <Text style={styles.title}>
              {t("completion.requestedTitle")}
            </Text>

            <Text style={styles.subtitle}>
              {t("completion.requestedSubtitle")}
            </Text>
          </View>

          {/* Submit Button */}
          <Pressable
            style={({ pressed }) => [
              styles.primaryButton,
              pressed && { opacity: 0.9, transform: [{ scale: 0.99 }] },
              saving && { opacity: 0.7 },
            ]}
            onPress={handleFinish}
            disabled={saving}
          >
            {saving ? (
              <ActivityIndicator color="#FFFFFF" />
            ) : (
              <Text style={styles.primaryButtonText}>
                {t("completion.finish")}
              </Text>
            )}
          </Pressable>

          <View style={{ height: 22 }} />
        </ScrollView>
      </View>
    );
  }

  // Completed screen
  return (
    <View style={styles.screen}>
      <Header />
      <ScrollView
        contentContainerStyle={styles.scroll}
        keyboardShouldPersistTaps="handled"
      >
        {/* Header */}
        <View style={styles.header}>
          <View style={styles.successBadge}>
            <Text style={styles.successBadgeText}>
              ✅ {t("completion.completedBadge")}
            </Text>
          </View>

          <Text style={styles.successTitle}>
            {t("completion.submittedTitle")}
          </Text>

          <Text style={styles.successSubtitle}>
            {t("completion.submittedSubtitle")}
          </Text>
        </View>

        {/* Success Icon */}
        <View style={styles.successIconContainer}>
          <View style={styles.successCircle}>
            <Text style={styles.checkIcon}>✓</Text>
          </View>
          <Text style={styles.successMessage}>
            {t("completion.completeMessage")}
          </Text>
        </View>

        {/* Start New Form Button */}
        <Pressable
          style={({ pressed }) => [
            styles.newFormButton,
            pressed && { opacity: 0.9, transform: [{ scale: 0.99 }] },
          ]}
          onPress={handleStartNew}
        >
          <Text style={styles.newFormButtonText}>
            {t("completion.startNewForm")}
          </Text>
        </Pressable>

        <View style={{ height: 22 }} />
      </ScrollView>
    </View>
  );
}

